// ========================================================================
// SYNC-PAYLOAD FÜR STELLENISTBERECHNUNG APP
// ========================================================================
// Workflow: #222 Stellenist-Sync
// Datum: 12.03.2026
//
// Wandelt die Untis-MSSQL-Ergebnisse in das JSON-Format um,
// das der POST /api/deputate/sync Endpoint erwartet.
//
// Erwartetes Format (syncPayloadSchema):
//   api_key, sync_datum, schuljahr_text?, term_id?, date_from?, date_to?,
//   lehrer: [{ teacher_id, name, vollname, personalnummer?, stammschule,
//             deputat, deputat_ges, deputat_gym, deputat_bk }]
// ========================================================================

const items = $input.all();

if (items.length === 0) {
  console.log('Stellenist-Sync: Keine Lehrer aus Untis geladen. Sync übersprungen.');
  return { json: { skip: true, reason: 'Keine Daten' } };
}

// Term-Infos aus erstem Item extrahieren (alle haben gleiche Periode)
const first = items[0].json;
const termId = first.TERM_ID;
const dateFrom = first.DateFrom_Formatted || null;
const dateTo = first.DateTo_Formatted || null;
const schuljahrText = first.Schuljahr_Text || null;

// API-Key aus n8n Environment Variable
// → n8n Settings > Variables > API_SYNC_KEY
const apiKey = $env.API_SYNC_KEY;
if (!apiKey) {
  throw new Error('Environment Variable API_SYNC_KEY ist nicht gesetzt! Bitte unter n8n Settings > Variables hinterlegen.');
}

// Payload zusammenbauen
const payload = {
  api_key: apiKey,
  sync_datum: new Date().toISOString().split('T')[0],
  schuljahr_text: schuljahrText,
  term_id: termId,
  date_from: dateFrom,
  date_to: dateTo,
  lehrer: items.map(item => {
    const d = item.json;
    return {
      teacher_id: d.TEACHER_ID,
      name: d.Name,
      vollname: d.Vollname,
      personalnummer: d.Personalnummer || null,
      stammschule: d.Stammschule || 'N/A',
      deputat: parseFloat(d.Deputat) || 0,
      deputat_ges: parseFloat(d.Deputat_GES) || 0,
      deputat_gym: parseFloat(d.Deputat_GYM) || 0,
      deputat_bk: parseFloat(d.Deputat_BK) || 0
    };
  })
};

console.log(`Stellenist-Sync: ${payload.lehrer.length} Lehrer, Periode ${termId}, Zeitraum ${dateFrom} – ${dateTo}`);

return { json: payload };

// ========================================================================
// ERFOLGS-LOG
// ========================================================================
const response = $input.first().json;

console.log('✅ Stellenist-Sync erfolgreich!');
console.log(`   Verarbeitet: ${response.verarbeitet} Lehrer`);
console.log(`   Fehler: ${response.fehler}`);
console.log(`   Monate: ${response.monate}`);
console.log(`   Nachricht: ${response.message}`);

return {
  json: {
    status: 'success',
    message: response.message,
    verarbeitet: response.verarbeitet,
    fehler: response.fehler,
    monate: response.monate,
    timestamp: new Date().toISOString()
  }
};

// ========================================================================
// FEHLER-LOG + WARNUNG
// ========================================================================
const response = $input.first().json;

const errorMsg = response.error || response.message || JSON.stringify(response);

console.error('❌ Stellenist-Sync FEHLGESCHLAGEN!');
console.error(`   Fehler: ${errorMsg}`);
console.error(`   Zeitpunkt: ${new Date().toISOString()}`);

// Fehler-Details für optionale E-Mail-Benachrichtigung
return {
  json: {
    status: 'error',
    error: errorMsg,
    timestamp: new Date().toISOString(),
    hinweis: 'Bitte prüfen: Läuft die Stellenist-App? Stimmt der API-Key? Ist die URL korrekt?'
  }
};
